Thought: <atomic> The fix requires pyreverse to check PEP 484 annotations on function parameters when inferring `self.attr = param` assignments. I'll write a self-contained Python script demonstrating the correct extraction logic and the patch needed in pyreverse's inference code.
Action: {"name": "python_exec", "args": {"code": "import ast
from typing import Optional

SOURCE = '''
class C(object):
    def __init__(self, a: str = None):
        self.a = a

class D:
    def __init__(self, count: int, name: str = 'x') -> None:
        self.count = count
        self.name = name
'''

def annotation_to_str(node) -> Optional[str]:
    if node is None:
        return None
    if isinstance(node, ast.Name):
        return node.id
    if isinstance(node, ast.Attribute):
        return node.attr
    if isinstance(node, ast.Subscript):
        outer = annotation_to_str(node.value)
        inner = annotation_to_str(node.slice)
        return f'{outer}[{inner}]' if outer else None
    if isinstance(node, ast.Constant):
        return str(node.value)
    return None

def extract_pep484_attrs(source: str) -> dict:
    tree = ast.parse(source)
    result = {}
    for cls in (n for n in ast.walk(tree) if isinstance(n, ast.ClassDef)):
        attrs = {}
        for func in (n for n in ast.walk(cls) if isinstance(n, ast.FunctionDef)):
            # map param name -> annotation string
            param_ann = {}
            for arg in func.args.args:
                ann_str = annotation_to_str(arg.annotation)
                if ann_str:
                    param_ann[arg.arg] = ann_str
            # find self.attr = param
            for stmt in ast.walk(func):
                if not isinstance(stmt, ast.Assign):
                    continue
                for tgt in stmt.targets:
                    if (isinstance(tgt, ast.Attribute)
                            and isinstance(tgt.value, ast.Name)
                            and tgt.value.id == 'self'
                            and tgt.attr not in attrs):
                        if isinstance(stmt.value, ast.Name) and stmt.value.id in param_ann:
                            attrs[tgt.attr] = param_ann[stmt.value.id]
            # find self.attr: Type = ...
            for stmt in ast.walk(func):
                if not isinstance(stmt, ast.AnnAssign):
                    continue
                tgt = stmt.target
                if (isinstance(tgt, ast.Attribute)
                        and isinstance(tgt.value, ast.Name)
                        and tgt.value.id == 'self'
                        and tgt.attr not in attrs):
                    ann_str = annotation_to_str(stmt.annotation)
                    if ann_str:
                        attrs[tgt.attr] = ann_str
        result[cls.name] = attrs
    return result

result = extract_pep484_attrs(SOURCE)
for cls_name, attrs in result.items():
    print(f'Class {cls_name}:')
    for attr, typ in sorted(attrs.items()):
        print(f'  {attr} : {typ}')
